const fullTextRaw = $input.first().json.text || "";
const fullText = fullTextRaw.replace(/\\n/g, "\n");

const blocks = fullText
  .split("##END##")
  .map(b => b.trim())
  .filter(Boolean);

return blocks.map(block => {

  const erro = block.match(/ERRO:\s*(.*)/i)?.[1] || "";
  const codigo = block.match(/CÓDIGO:\s*(\d+)/i)?.[1] || null;
  const causa = block.match(/CAUSA:\s*(.*)/i)?.[1] || "";
  const solucao = block.match(/SOLUÇÃO:\s*(.*)/i)?.[1] || "";

  const content = `
Rejeição ${codigo} da SEFAZ.
Erro: ${erro}
Causa: ${causa}
Solução: ${solucao}
`.trim();

  return {
    json: {
      codigo,
      erro,
      causa,
      solucao,
      content
    }
  };
});

const embeddingsItems = $input.all(); // itens que vêm do HTTP (OpenAI)
const chunksItems = $items("Text Preprocessing – Chunk Generator");

const now = new Date().toISOString();

return embeddingsItems.map((embItem, i) => {
  const chunk = chunksItems[i]?.json ?? {};
  const embedding = embItem.json?.data?.[0]?.embedding ?? null;

  return {
    json: {
      codigo: chunk.codigo ?? null,
      erro: chunk.erro ?? null,
      causa: chunk.causa ?? null,
      solucao: chunk.solucao ?? null,
      content: chunk.content ?? null,
      embedding,
      createdAt: now,
    },
  };
});
